/**
 * Configuration parameters for the AI model.
 * @export
 * @interface ModelConfig
 */
export interface ModelConfig {
  /**
   * The repetition penalty coefficient: 1 means no penalty, values greater than 1 encourage generating non-repetitive tokens, and values less than 1 tend to generate repetitive tokens. The recommended range is [1, 1.2].
   * @type {number}
   * @memberof ModelConfig
   */
  frequency_penalty?: number;
  /**
   * The maximum number of tokens that can be generated in the chat completion. Default value is 1024.
   * @type {number}
   * @memberof ModelConfig
   */
  max_tokens?: number;
  /**
   * How many chat completion choices to generate for each input message. Note that you will be charged based on the number of generated tokens across all of the choices. Keep n as 1 to minimize costs.
   * @type {number}
   * @memberof ModelConfig
   */
  n?: number;
  /**
   * What sampling temperature to use, between 0 and 2. Higher values like 0.8 will make the output more random, while lower values like 0.2 will make it more focused and deterministic. We generally recommend altering this or top_p but not both.
   * @type {number}
   * @memberof ModelConfig
   */
  temperature?: number;
  /**
   * An alternative to sampling with temperature, called nucleus sampling, where the model considers the results of the tokens with top_p probability mass. So 0.1 means only the tokens comprising the top 10% probability mass are considered. We generally recommend altering this or temperature but not both.
   * @type {number}
   * @memberof ModelConfig
   */
  top_p?: number;
}
